import React, { useState, useEffect } from 'react';
import { getRecords, clearRecords, getTotalEcoPoints, getTotalGreenCredits, getTotalCO2, GREEN_CREDIT_MULTIPLIER } from '../services/store';
import { calcImpact, calcEcoScore, generateInsights, IMPACT } from '../services/api';
import WastePieChart from '../components/WastePieChart';
import DailyBarChart from '../components/DailyBarChart';
import useScrollReveal from '../hooks/useScrollReveal';
import './Dashboard.css';

export default function Dashboard() {
  const [records, setRecords] = useState([]);
  const [showClearConfirm, setShowClear] = useState(false);
  const [titleTyped, setTitleTyped] = useState('');
  const [now, setNow] = useState(new Date());

  useEffect(() => { setRecords(getRecords()); }, []);

  // Live clock
  useEffect(() => {
    const iv = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(iv);
  }, []);

  /* Typewriter for title */
  useEffect(() => {
    const T = 'Analytics';
    let i = 0;
    const iv = setInterval(() => {
      setTitleTyped(T.slice(0, i + 1));
      i++;
      if (i >= T.length) clearInterval(iv);
    }, 70);
    return () => clearInterval(iv);
  }, []);

  const total = records.length;
  const recyclable = records.filter(r => r.category === 'Recyclable').length;
  const biodegradable = records.filter(r => r.category === 'Biodegradable').length;
  const hazardous = records.filter(r => r.category === 'Hazardous').length;
  const impact = calcImpact(records);
  const ecoScore = calcEcoScore(records);
  const insights = generateInsights(records);
  const totalEcoPoints = getTotalEcoPoints(records);
  const totalGreenCredits = getTotalGreenCredits(records);
  const totalCO2 = getTotalCO2(records);
  const hazardAlert = hazardous >= 3;

  const commScans = (total * 180 + 8420).toLocaleString();
  const commCO2 = (impact.co2 * 180 + 1247).toFixed(1) + ' kg';
  const commPts = (totalEcoPoints * 180 + 44800).toLocaleString();

  useScrollReveal([records]);
  const pct = n => total ? Math.round((n / total) * 100) : 0;

  const scoreColor = ecoScore >= 70 ? '#00FF87' : ecoScore >= 40 ? '#F5A623' : '#f87171';
  const scoreLabel = ecoScore >= 70 ? 'EXCELLENT' : ecoScore >= 40 ? 'GOOD PROGRESS' : 'NEEDS WORK';

  const recyclingRate = pct(recyclable);
  const disposalRate = pct(recyclable + biodegradable);
  const hazardControl = hazardous === 0 ? 100 : Math.max(0, 100 - Math.round((hazardous / total) * 200));

  function handleClear() { clearRecords(); setRecords([]); setShowClear(false); }

  const timeStr = now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
  const dateStr = now.toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' });

  return (
    <div className="page-content dashboard-page">

      {/* ── HUD Header Bar ── */}
      <div className="hud-header">
        <div className="hud-clock-block">
          <span className="hud-time">{timeStr}</span>
          <span className="hud-date">{dateStr}</span>
        </div>
        <div className="hud-title-block">
          <span className="hud-brand">VERDANT</span>
          <h1 className="dash-title">{titleTyped}<span className="dash-cursor">|</span></h1>
          <span className="hud-subtitle">SUSTAINABILITY INTELLIGENCE SYSTEM</span>
        </div>
        <div className="hud-status-block">
          <div className="hud-status-dot" />
          <span className="hud-status-text">SYSTEM ONLINE</span>
          {total > 0 && (
            <button className="clear-btn" onClick={() => setShowClear(true)} title="Clear all data">✕</button>
          )}
        </div>
      </div>

      {total === 0 ? <EmptyState /> : (
        <>
          {/* ⚠️ Hazard Alert */}
          {hazardAlert && (
            <div className="hazard-alert" data-reveal>
              <span className="hazard-alert-icon">⚠️</span>
              <div>
                <p className="hazard-alert-title">HAZARDOUS WASTE ALERT</p>
                <p className="hazard-alert-msg">
                  {hazardous} hazardous items detected — dispose at a certified collection point immediately.
                </p>
              </div>
            </div>
          )}

          {/* ── Live Stats Strip ── */}
          <div className="live-stats-strip" data-reveal>
            <LiveStat label="TOTAL SCANNED" value={total} unit="items" color="#00FF87" />
            <div className="live-stat-divider" />
            <LiveStat label="CO₂ PREVENTED" value={totalCO2.toFixed(2)} unit="kg" color="#00FF87" />
            <div className="live-stat-divider" />
            <LiveStat label="GREEN CREDITS" value={totalGreenCredits} unit="pts" color="#a3e635" />
            <div className="live-stat-divider" />
            <LiveStat label="ECO POINTS" value={totalEcoPoints} unit="pts" color="#00FF87" />
            <div className="live-stat-divider" />
            <LiveStat label="HAZARDOUS" value={hazardous} unit="items" color={hazardous > 0 ? '#f87171' : '#00FF87'} />
          </div>

          {/* ── Main HUD Grid ── */}
          <div className="hud-main-grid" data-reveal data-reveal-delay="60">

            {/* LEFT — Eco Score Gauge */}
            <div className="hud-panel gauge-panel">
              <div className="panel-label">SUSTAINABILITY SCORE</div>
              <BigGauge score={ecoScore} color={scoreColor} label={scoreLabel} />
              <div className="gauge-bars">
                <SegBar label="RECYCLING RATE" value={recyclingRate} color="#60a5fa" />
                <SegBar label="CORRECT DISPOSAL" value={disposalRate} color="#00FF87" />
                <SegBar label="HAZARD CONTROL" value={hazardControl} color="#f87171" />
              </div>
            </div>

            {/* RIGHT — Waste Breakdown */}
            <div className="hud-panel breakdown-panel">
              <div className="panel-label">WASTE DISTRIBUTION</div>
              <div className="breakdown-ring-chart">
                <WastePieChart records={records} />
              </div>
              <div className="breakdown-stats">
                <BreakStat icon="♻️" label="Recyclable" count={recyclable} pct={pct(recyclable)} color="#60a5fa" />
                <BreakStat icon="🌿" label="Biodegradable" count={biodegradable} pct={pct(biodegradable)} color="#4ade80" />
                <BreakStat icon="⚠️" label="Hazardous" count={hazardous} pct={pct(hazardous)} color="#f87171" />
              </div>
            </div>
          </div>

          {/* ── Energy / Impact Readout (Car-dash style) ── */}
          <div className="hud-impact-strip" data-reveal data-reveal-delay="100">
            <div className="panel-label" style={{ marginBottom: 14 }}>ENVIRONMENTAL IMPACT READOUT</div>
            <div className="impact-readout-grid">
              <ImpactReadout icon="🌫️" value={impact.co2.toFixed(2)} unit="kg" label="CO₂ PREVENTED" color="#00FF87" />
              <ImpactReadout icon="🗑️" value={impact.landfill.toFixed(2)} unit="kg" label="LANDFILL AVOIDED" color="#a3e635" />
              <ImpactReadout icon="⚡" value={impact.energy.toFixed(2)} unit="kWh" label="ENERGY SAVED" color="#facc15" />
              <ImpactReadout icon="🌳" value={impact.trees.toFixed(1)} unit="days" label="TREE EQUIVALENT" color="#4ade80" />
            </div>
          </div>

          {/* ── Daily Trends ── */}
          <section className="dash-section" data-reveal data-reveal-delay="130">
            <div className="panel-label" style={{ marginBottom: 12 }}>DAILY TRENDS · LAST 7 DAYS</div>
            <div className="chart-card"><DailyBarChart records={records} /></div>
          </section>

          {/* ── Green Credits ── */}
          <section className="dash-section" data-reveal data-reveal-delay="150">
            <div className="panel-label" style={{ marginBottom: 12 }}>GREEN CREDITS</div>
            <div className="green-credits-card">
              <div className="gc-header">
                <div className="gc-icon-wrap">
                  <span className="gc-icon">🟢</span>
                  <div className="gc-icon-glow" />
                </div>
                <div>
                  <p className="gc-total-num">{totalGreenCredits}</p>
                  <p className="gc-total-label">TOTAL CREDITS EARNED</p>
                </div>
                <p className="gc-formula-inline">Credits = CO₂ × multiplier × 10</p>
              </div>
              <div className="gc-breakdown">
                <GcRow icon="♻️" label="Recyclable" mult={GREEN_CREDIT_MULTIPLIER.Recyclable} count={recyclable} color="#60a5fa" records={records} />
                <GcRow icon="🌿" label="Biodegradable" mult={GREEN_CREDIT_MULTIPLIER.Biodegradable} count={biodegradable} color="#4ade80" records={records} />
                <GcRow icon="⚠️" label="Hazardous" mult={GREEN_CREDIT_MULTIPLIER.Hazardous} count={hazardous} color="#f87171" records={records} />
              </div>
              <div className="gc-redeem">
                <span>🎟️</span>
                <p>Redeemable for: transit discounts · campus incentives · eco rewards</p>
              </div>
            </div>
          </section>

          {/* ── AI Insights ── */}
          <section className="dash-section" data-reveal data-reveal-delay="180">
            <div className="panel-label" style={{ marginBottom: 12 }}>AI INSIGHTS</div>
            <TerminalInsights insights={insights} />
          </section>

          {/* ── Activity Feed ── */}
          <section className="dash-section" data-reveal data-reveal-delay="210">
            <div className="panel-label" style={{ marginBottom: 12 }}>RECENT ACTIVITY</div>
            <div className="activity-feed">
              <div className="activity-timeline-line" />
              {records.slice(0, 20).map((r, i) => (
                <ActivityItem key={r.id} record={r} index={i} />
              ))}
              {records.length > 20 && (
                <p className="activity-more">+ {records.length - 20} more items</p>
              )}
            </div>
          </section>

          {/* ── Community + Leaderboard ── */}
          <div className="hud-bottom-grid" data-reveal data-reveal-delay="240">
            <div>
              <div className="panel-label" style={{ marginBottom: 12 }}>COMMUNITY IMPACT</div>
              <div className="community-card">
                <CommStat icon="👥" value="2,341" label="Active participants" />
                <CommStat icon="🌍" value={commCO2} label="Community CO₂ prevented" />
                <CommStat icon="♻️" value={commScans} label="Items correctly sorted" />
                <CommStat icon="🌱" value={commPts} label="Community eco-points" />
              </div>
            </div>
            <div>
              <div className="panel-label" style={{ marginBottom: 12 }}>TOP CONTRIBUTORS</div>
              <div className="leaderboard-card">
                {buildLeaderboard(totalEcoPoints).map(e => (
                  <LeaderboardRow key={e.name} {...e} />
                ))}
              </div>
            </div>
          </div>
        </>
      )}

      {/* Clear confirm modal */}
      {showClearConfirm && (
        <div className="modal-overlay">
          <div className="modal-card">
            <div className="modal-icon">🗑️</div>
            <h3 className="modal-title">Clear All Data?</h3>
            <p className="modal-body">This permanently deletes all scan history and resets your dashboard.</p>
            <div className="modal-actions">
              <button className="modal-btn modal-btn-cancel" onClick={() => setShowClear(false)}>Cancel</button>
              <button className="modal-btn modal-btn-danger" onClick={handleClear}>Clear All</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ── HUD Live Stat ── */
function LiveStat({ label, value, unit, color }) {
  return (
    <div className="live-stat">
      <span className="live-stat-value" style={{ color }}>{value}</span>
      <span className="live-stat-unit" style={{ color }}>{unit}</span>
      <span className="live-stat-label">{label}</span>
    </div>
  );
}

/* ── Big Radial Gauge (speedometer style) ── */
function BigGauge({ score, color, label }) {
  const R = 90;
  // Arc goes from -210° to +30° (240° sweep) starting from bottom-left
  const toRad = d => (d * Math.PI) / 180;
  const startAngle = -210; // degrees
  const sweepDeg = 240;
  const endAngle = startAngle + sweepDeg * (score / 100);
  const cx = 110, cy = 110;

  function describeArc(cx, cy, r, startDeg, endDeg) {
    const s = toRad(startDeg);
    const e = toRad(endDeg);
    const x1 = cx + r * Math.cos(s);
    const y1 = cy + r * Math.sin(s);
    const x2 = cx + r * Math.cos(e);
    const y2 = cy + r * Math.sin(e);
    const large = endDeg - startDeg > 180 ? 1 : 0;
    return `M ${x1} ${y1} A ${r} ${r} 0 ${large} 1 ${x2} ${y2}`;
  }

  // Tick marks
  const ticks = Array.from({ length: 21 }, (_, i) => {
    const angleDeg = startAngle + (sweepDeg / 20) * i;
    const rad = toRad(angleDeg);
    const major = i % 5 === 0;
    const r1 = major ? R - 10 : R - 6;
    return {
      x1: cx + R * Math.cos(rad),
      y1: cy + R * Math.sin(rad),
      x2: cx + r1 * Math.cos(rad),
      y2: cy + r1 * Math.sin(rad),
      major,
    };
  });

  return (
    <div className="big-gauge-wrap">
      <svg viewBox="0 0 220 180" className="big-gauge-svg">
        {/* Track arc */}
        <path
          d={describeArc(cx, cy, R, startAngle, startAngle + sweepDeg)}
          fill="none"
          stroke="rgba(255,255,255,0.06)"
          strokeWidth="10"
          strokeLinecap="round"
        />
        {/* Fill arc */}
        {score > 0 && (
          <path
            d={describeArc(cx, cy, R, startAngle, endAngle)}
            fill="none"
            stroke={color}
            strokeWidth="10"
            strokeLinecap="round"
            style={{ filter: `drop-shadow(0 0 10px ${color})`, transition: 'all 1.5s ease' }}
          />
        )}
        {/* Tick marks */}
        {ticks.map((t, i) => (
          <line key={i} x1={t.x1} y1={t.y1} x2={t.x2} y2={t.y2}
            stroke={t.major ? 'rgba(255,255,255,0.25)' : 'rgba(255,255,255,0.1)'}
            strokeWidth={t.major ? 2 : 1} />
        ))}
        {/* Score labels */}
        {[0, 25, 50, 75, 100].map((v, i) => {
          const angleDeg = startAngle + (sweepDeg / 100) * v;
          const rad = toRad(angleDeg);
          const lr = R - 20;
          return (
            <text key={i}
              x={cx + lr * Math.cos(rad)} y={cy + lr * Math.sin(rad)}
              textAnchor="middle" dominantBaseline="middle"
              fontSize="7" fill="rgba(255,255,255,0.3)" fontFamily="JetBrains Mono, monospace"
            >{v}</text>
          );
        })}
        {/* Center score */}
        <text x={cx} y={cy - 8} textAnchor="middle" fontSize="36" fontWeight="900"
          fill={color} fontFamily="Outfit, sans-serif"
          style={{ filter: `drop-shadow(0 0 12px ${color})` }}
        >{score}</text>
        <text x={cx} y={cy + 14} textAnchor="middle" fontSize="9"
          fill="rgba(255,255,255,0.3)" fontFamily="JetBrains Mono, monospace"
        >/ 100</text>
        <text x={cx} y={cy + 30} textAnchor="middle" fontSize="8" fontWeight="700"
          fill={color} fontFamily="Outfit, sans-serif" letterSpacing="2"
        >{label}</text>
      </svg>
    </div>
  );
}

/* ── Segmented Battery-style Bar ── */
function SegBar({ label, value, color }) {
  const SEGS = 20;
  const filled = Math.round((value / 100) * SEGS);
  return (
    <div className="seg-bar-row">
      <span className="seg-bar-label">{label}</span>
      <div className="seg-bar-track">
        {Array.from({ length: SEGS }, (_, i) => (
          <div key={i} className={`seg-bar-cell${i < filled ? ' filled' : ''}`}
            style={i < filled ? { background: color, boxShadow: `0 0 6px ${color}` } : {}} />
        ))}
      </div>
      <span className="seg-bar-pct" style={{ color }}>{value}%</span>
    </div>
  );
}

/* ── Impact Readout Panel (car-dash style) ── */
function ImpactReadout({ icon, value, unit, label, color }) {
  return (
    <div className="impact-readout-cell">
      <span className="ir-icon">{icon}</span>
      <div className="ir-value-wrap">
        <span className="ir-value" style={{ color }}>{value}</span>
        <span className="ir-unit">{unit}</span>
      </div>
      <span className="ir-label">{label}</span>
      <div className="ir-bar">
        <div className="ir-bar-fill" style={{ background: color, boxShadow: `0 0 8px ${color}` }} />
      </div>
    </div>
  );
}

/* ── Breakdown stat under pie ── */
function BreakStat({ icon, label, count, pct, color }) {
  return (
    <div className="break-stat">
      <span className="break-stat-icon">{icon}</span>
      <div className="break-stat-info">
        <span className="break-stat-label">{label}</span>
        <div className="break-stat-bar-track">
          <div className="break-stat-bar-fill" style={{ width: pct + '%', background: color, boxShadow: `0 0 6px ${color}` }} />
        </div>
      </div>
      <span className="break-stat-count" style={{ color }}>{count} <span className="break-stat-pct">({pct}%)</span></span>
    </div>
  );
}

function GcRow({ icon, label, mult, count, color, records }) {
  const total = records.filter(r => r.category === label).reduce((s, r) => s + (r.green_credits || 0), 0);
  return (
    <div className="ep-row">
      <div className="ep-row-left">
        <span className="ep-row-icon">{icon}</span>
        <div>
          <p className="ep-row-label">{label}</p>
          <p className="ep-row-count">×{mult} multiplier · {count} item{count !== 1 ? 's' : ''}</p>
        </div>
      </div>
      <span className="ep-row-pts" style={{ color }}>{total} <span className="ep-pts-unit">credits</span></span>
    </div>
  );
}

function ActivityItem({ record, index }) {
  const imp = IMPACT[record.category] || {};
  const dt = new Date(record.timestamp);
  const timeStr = dt.toLocaleDateString('en-IN', { day: '2-digit', month: 'short' })
    + ' · ' + dt.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
  return (
    <div className="activity-item" style={{ '--ai-color': imp.color, '--ai-delay': `${index * 0.05}s` }}>
      <div className="activity-dot" />
      <span className="activity-icon">{imp.icon}</span>
      <div className="activity-info">
        <div className="activity-top-row">
          <p className="activity-category" style={{ color: imp.color }}>
            {record.category}{record.object_detected ? ` · ${record.object_detected}` : ''}
          </p>
          {record.green_credits ? (
            <span className="activity-gc-badge">🟢 {record.green_credits}</span>
          ) : null}
        </div>
        {record.co2_saved > 0 && (
          <p className="activity-co2">🌫️ {record.co2_saved.toFixed(2)} kg CO₂ prevented</p>
        )}
        <p className="activity-time">{timeStr}</p>
      </div>
    </div>
  );
}

function CommStat({ icon, value, label }) {
  return (
    <div className="comm-stat">
      <span className="comm-stat-icon">{icon}</span>
      <p className="comm-stat-value">{value}</p>
      <p className="comm-stat-label">{label}</p>
    </div>
  );
}

function LeaderboardRow({ rank, name, pts, isUser }) {
  const medal = rank === 1 ? '🥇' : rank === 2 ? '🥈' : rank === 3 ? '🥉' : rank;
  return (
    <div className={`lb-row${isUser ? ' lb-you' : ''}`}>
      <span className="lb-rank">{medal}</span>
      <span className="lb-name">{name}{isUser ? ' (You)' : ''}</span>
      <span className="lb-pts">{pts}<span className="lb-pts-unit"> pts</span></span>
    </div>
  );
}

/* Terminal-style AI insights */
function TerminalInsights({ insights }) {
  const [displayed, setDisplayed] = useState([]);
  const [current, setCurrent] = useState('');
  const [lineIdx, setLineIdx] = useState(0);
  const [charIdx, setCharIdx] = useState(0);

  useEffect(() => {
    if (!insights.length || lineIdx >= insights.length) return;
    const line = insights[lineIdx];
    if (charIdx < line.length) {
      const t = setTimeout(() => {
        setCurrent(line.slice(0, charIdx + 1));
        setCharIdx(c => c + 1);
      }, 22);
      return () => clearTimeout(t);
    } else {
      const t = setTimeout(() => {
        setDisplayed(d => [...d, line]);
        setCurrent('');
        setCharIdx(0);
        setLineIdx(i => i + 1);
      }, 400);
      return () => clearTimeout(t);
    }
  }, [insights, lineIdx, charIdx]);

  return (
    <div className="terminal-card">
      <div className="terminal-header">
        <div className="terminal-dots">
          <span style={{ background: '#f87171' }} />
          <span style={{ background: '#F5A623' }} />
          <span style={{ background: '#4ade80' }} />
        </div>
        <span className="terminal-title">AI_INSIGHTS.log</span>
      </div>
      <div className="terminal-body">
        <p className="terminal-prompt">{'>'} Analysing waste patterns…</p>
        {displayed.map((ins, i) => (
          <p key={i} className="terminal-line">
            <span className="terminal-arrow">›</span> {ins}
          </p>
        ))}
        {lineIdx < insights.length && (
          <p className="terminal-line terminal-active">
            <span className="terminal-arrow">›</span> {current}
            <span className="terminal-cursor-blink">▮</span>
          </p>
        )}
      </div>
    </div>
  );
}

const MOCK_CONTRIBUTORS = [
  { name: 'Priya S.', pts: 342 }, { name: 'Rahul M.', pts: 287 },
  { name: 'Ananya K.', pts: 251 }, { name: 'Vikram T.', pts: 198 },
  { name: 'Meera P.', pts: 167 },
];
function buildLeaderboard(userPts) {
  return [...MOCK_CONTRIBUTORS, { name: 'You', pts: userPts, isUser: true }]
    .sort((a, b) => b.pts - a.pts)
    .map((e, i) => ({ ...e, rank: i + 1 }));
}
function EmptyState() {
  return (
    <div className="empty-state">
      <div className="empty-icon-wrap">
        <span className="empty-icon">📊</span>
        <div className="empty-icon-glow" />
      </div>
      <h3 className="empty-title">No Scans Yet</h3>
      <p className="empty-desc">Head to the Scan tab and classify your first waste item — your sustainability data will appear here.</p>
    </div>
  );
}
